## Using the headless hook

When you need full control over the upload UI — a custom progress bar, inline file list, or your own drag-and-drop area — use the `useUploadKit` hook directly:

```tsx title="src/components/CustomUploader.tsx"

export function CustomUploader() {
  const { upload, files, isUploading } = useUploadKit({
    route: 'imageUploader',
    onUploadComplete: (uploadedFiles) => {
      console.log('Done:', uploadedFiles);
    },
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) upload(file);
  };

  return (
    <div>
      <input type="file" accept="image/*" onChange={handleChange} disabled={isUploading} />
      {isUploading && <p>Uploading...</p>}
      {files.map((f) => (
        <div key={f.id}>
          <span>{f.name}</span>
          <progress value={f.progress} max={100} />
        </div>
      ))}
    </div>
  );
}
```

## Using the core client directly

For maximum control, you can use `createProxyClient` from `@uploadkitdev/core` without any React dependency. The proxy client talks to your local backend endpoint (which holds the API key) rather than the UploadKit API directly:

```typescript title="src/lib/upload.ts"

const client = createProxyClient({
  endpoint: '/api/uploadkit', // your backend endpoint, not the UploadKit API
});

export async function uploadFile(
  file: File,
  onProgress?: (pct: number) => void,
) {
  const result = await client.upload({
    file,
    route: 'imageUploader',
    onProgress,
  });
  return result; // { id, key, name, size, type, url, status, createdAt }
}
```

This is useful when integrating uploads into form libraries, file managers, or non-React contexts.

Avatar uploads have specific requirements: a single file, small size limit, and the ability to replace an existing avatar without leaving orphaned files. This guide covers all three.

## 1. Configure the file route

```typescript title="app/api/uploadkit/route.ts"

const router = {
  avatarUploader: {
    maxFileSize: '2MB',
    maxFileCount: 1,
    allowedTypes: ['image/jpeg', 'image/png', 'image/webp'],
    middleware: async ({ req }) => {
      const session = await getSession(req);
      if (!session) throw new Error('Unauthorized');

      // Pass the existing avatar key so we can delete it after upload
      const user = await db.users.findById(session.user.id);
      return {
        userId: session.user.id,
        existingAvatarKey: user.avatarKey ?? null,
      };
    },
    onUploadComplete: async ({ file, metadata }) => {
      // Delete the old avatar from storage
      if (metadata.existingAvatarKey) {
        await uploadkit.files.delete(metadata.existingAvatarKey);
      }

      // Save the new avatar
      await db.users.updateById(metadata.userId, {
        avatarUrl: file.url,
        avatarKey: file.key,
      });
    },
  },
} satisfies FileRouter;

export const { GET, POST } = createUploadKitHandler({ router });
```

  Store both `file.url` and `file.key` for avatar files. The URL is displayed to users; the key is used to delete the old avatar when the user uploads a new one.

## 2. Add the upload button with circular preview

