```css
/* Style the button */
[data-uk-element="uk-button"] {
  background: linear-gradient(135deg, #6366f1, #8b5cf6);
  border-radius: 999px;
}

/* Style the dropzone when dragging */
[data-uk-element="uk-dropzone"][data-state="uploading"] {
  opacity: 0.6;
  pointer-events: none;
}

/* Style file items */
[data-uk-element="uk-file-item"] {
  background: #f8f9fa;
  border-radius: 8px;
}
