## Basic usage

```tsx

export default function Page() {
  return (
    <UploadDropzone
      route="imageUploader"
      onUploadComplete={(results) => {
        // results is UploadResult[] — called when ALL files finish
        console.log('Uploaded:', results.map((r) => r.url));
